     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import { useCallback, useEffect, useRef, useState } from "react";
     5→import { QRCodeSVG } from "qrcode.react";
     6→import { useCamera } from "@/hooks/useCamera";
     7→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     8→import { usePoseDetection } from "@/hooks/usePoseDetection";
     9→import { useMiraVideoAvatar } from "@/hooks/useMiraVideoAvatar";
    10→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
    11→import { parseEmotionTag, detectEmotionFromText } from "@/lib/emotion-parser";
    12→import { MiraVideoAvatar } from "@/components/ui/mira-video-avatar";
    13→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    14→import { ClothingCanvas } from "@/components/mirror/ClothingCanvas";
    15→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    16→import PriceStrip, { type PriceStripItem } from "@/components/mirror/PriceStrip";
    17→import { socket } from "@/lib/socket";
    18→import { skipQueueUser } from "@/lib/api";
    19→import type { DetectedGesture, GestureType } from "@/types/gestures";
    20→import type { PoseResult } from "@/types/pose";
    21→import type { ClothingItem } from "@/types/clothing";
    22→import { mapToClothingItems } from "@/lib/map-clothing-items";
    23→
    24→type KioskState = "attract" | "waiting" | "session";
    25→
    26→interface ActiveUser {
    27→  id: string;
    28→  name: string;
    29→}
    30→
    31→const PHONE_URL = process.env.NEXT_PUBLIC_PHONE_URL || "https://mirrorless.vercel.app/phone";
    32→const WAITING_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes
    33→
    34→export default function MirrorPageWrapper() {
    35→  return (
    36→    <Suspense fallback={null}>
    37→      <MirrorPage />
    38→    </Suspense>
    39→  );
    40→}
    41→
    42→function MirrorPage() {
    43→  // Kiosk state
    44→  const [kioskState, setKioskState] = useState<KioskState>("attract");
    45→  const [activeUser, setActiveUser] = useState<ActiveUser | null>(null);
    46→  const waitingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    47→
    48→  // Camera + gesture recognition
    49→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    50→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    51→  const gestureKeyRef = useRef(0);
    52→  const [gestureKey, setGestureKey] = useState(0);
    53→
    54→  // Session state
    55→  const [sessionActive, setSessionActive] = useState(false);
    56→  const [isStarting, setIsStarting] = useState(false);
    57→
    58→  // Pose detection + clothing overlay state
    59→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    60→
    61→  interface CanvasOutfit {
    62→    name: string;
    63→    items: ClothingItem[];
    64→    productInfo: PriceStripItem[];
    65→  }
    66→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    67→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    68→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    69→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    70→
    71→  // Mira video avatar + voice
    72→  const mira = useMiraVideoAvatar();
    73→  const stt = useDeepgramSTT();
    74→
    75→  // Queue transcripts while mira is speaking, send when quiet
    76→  const pendingTranscriptRef = useRef<string | null>(null);
    77→
    78→  // Accumulate full response text before delivering
    79→  const responseAccumulatorRef = useRef<string>("");
    80→
    81→  // Current user ID for session (from queue, not URL)
    82→  const userId = activeUser?.id ?? null;
    83→
    84→  // Pose detection for clothing overlay
    85→  const handlePoseUpdate = useCallback((result: PoseResult) => {
    86→    setCurrentPose(result);
    87→  }, []);
    88→
    89→  usePoseDetection({
    90→    videoRef,
    91→    isVideoReady: isCameraReady,
    92→    onPoseUpdate: handlePoseUpdate,
    93→  });
    94→
    95→  // Connect socket and join mirror room
    96→  useEffect(() => {
    97→    socket.connect();
    98→    socket.emit("join_mirror_room");
    99→
   100→    return () => {
   101→      socket.disconnect();
   102→    };
   103→  }, []);
   104→
   105→  // Join user-specific room when active user changes
   106→  useEffect(() => {
   107→    if (userId) {
   108→      socket.emit("join_room", { user_id: userId });
   109→    }
   110→  }, [userId]);
   111→
   112→  // Listen for queue_updated events (drives attract ↔ waiting transitions)
   113→  useEffect(() => {
   114→    const handleQueueUpdated = (data: {
   115→      active_user: ActiveUser | null;
   116→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   117→    }) => {
   118→      console.log("[Mirror] queue_updated:", data);
   119→      if (kioskState === "session") return; // Don't interrupt active sessions
   120→
   121→      if (data.active_user) {
   122→        setActiveUser(data.active_user);
   123→        setKioskState("waiting");
   124→      } else {
   125→        setActiveUser(null);
   126→        setKioskState("attract");
   127→      }
   128→    };
   129→
   130→    socket.on("queue_updated", handleQueueUpdated);
   131→    return () => {
   132→      socket.off("queue_updated", handleQueueUpdated);
   133→    };
   134→  }, [kioskState]);
   135→
   136→  // 2-minute timeout in waiting state
   137→  useEffect(() => {
   138→    if (kioskState === "waiting" && activeUser) {
   139→      waitingTimerRef.current = setTimeout(() => {
   140→        console.log("[Mirror] Waiting timeout — auto-skipping user");
   141→        skipQueueUser(activeUser.id).catch(() => {});
   142→      }, WAITING_TIMEOUT_MS);
   143→    }
   144→    return () => {
   145→      if (waitingTimerRef.current) {
   146→        clearTimeout(waitingTimerRef.current);
   147→        waitingTimerRef.current = null;
   148→      }
   149→    };
   150→  }, [kioskState, activeUser]);
   151→
   152→  // Listen for session_active from backend
   153→  useEffect(() => {
   154→    const handleSessionActive = () => {
   155→      setKioskState("session");
   156→      setSessionActive(true);
   157→      setIsStarting(false);
   158→      setCanvasOutfits([]);
   159→      setCanvasOutfitIndex(0);
   160→      mira.startSession();
   161→      stt.startListening();
   162→    };
   163→
   164→    socket.on("session_active", handleSessionActive);
   165→    return () => {
   166→      socket.off("session_active", handleSessionActive);
   167→    };
   168→    // eslint-disable-next-line react-hooks/exhaustive-deps
   169→  }, []);
   170→
   171→  // Listen for mira_speech events (streamed text from AI)
   172→  useEffect(() => {
   173→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   174→      // Fallback session detection
   175→      if (!sessionActive && !isStarting) {
   176→        setKioskState("session");
   177→        setSessionActive(true);
   178→        setIsStarting(false);
   179→        mira.startSession();
   180→        stt.startListening();
   181→      }
   182→
   183→      if (data.is_chunk !== false) {
   184→        if (!data.text) return;
   185→        console.log("[Mirror] mira_speech chunk received");
   186→        responseAccumulatorRef.current += data.text;
   187→        mira.setOrbState("thinking");
   188→        mira.setEmotion("thinking");
   189→      } else {
   190→        if (data.text) {
   191→          responseAccumulatorRef.current += data.text;
   192→        }
   193→        const fullText = responseAccumulatorRef.current;
   194→        responseAccumulatorRef.current = "";
   195→        console.log("[Mirror] Agent full response:", fullText);
   196→        if (!fullText) return;
   197→
   198→        // Parse emotion tag first, then detect from content as fallback
   199→        let { emotion, cleanText } = parseEmotionTag(fullText);
   200→
   201→        // If no explicit emotion tag, try to detect from content
   202→        if (emotion === "idle") {
   203→          emotion = detectEmotionFromText(cleanText);
   204→        }
   205→
   206→        console.log("[Mirror] Parsed emotion:", emotion);
   207→        mira.speak(cleanText, emotion);
   208→      }
   209→    };
   210→
   211→    socket.on("mira_speech", handleSpeech);
   212→    return () => {
   213→      socket.off("mira_speech", handleSpeech);
   214→    };
   215→    // eslint-disable-next-line react-hooks/exhaustive-deps
   216→  }, [sessionActive, isStarting]);
   217→
   218→  // Listen for tool_result events (product recommendations + voice messages)
   219→  useEffect(() => {
   220→    const handleToolResult = (data: {
   221→      type?: string;
   222→      tool?: string;
   223→      items?: { title: string; price?: string; [key: string]: unknown }[];
   224→      text?: string;
   225→      emotion?: string;
   226→      outfit_name?: string;
   227→    }) => {
   228→      if (data.type === "display_product" && data.items) {
   229→        const clothingItems = mapToClothingItems(data.items);
   230→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   231→          title: it.title,
   232→          price: it.price,
   233→        }));
   234→        if (clothingItems.length > 0) {
   235→          setCanvasOutfits((prev) => {
   236→            const next = [...prev, {
   237→              name: data.outfit_name || `Outfit ${prev.length + 1}`,
   238→              items: clothingItems,
   239→              productInfo: priceInfo,
   240→            }];
   241→            setCanvasOutfitIndex(next.length - 1);
   242→            return next;
   243→          });
   244→        }
   245→        return;
   246→      }
   247→      if (data.type === "voice_message" && data.text) {
   248→        const emotion = detectEmotionFromText(data.text);
   249→        mira.speak(data.text, emotion);
   250→        return;
   251→      }
   252→    };
   253→
   254→    socket.on("tool_result", handleToolResult);
   255→    return () => {
   256→      socket.off("tool_result", handleToolResult);
   257→    };
   258→    // eslint-disable-next-line react-hooks/exhaustive-deps
   259→  }, [mira.speak]);
   260→
   261→  // Listen for session_ended — return to attract or waiting
   262→  useEffect(() => {
   263→    const handleSessionEnded = () => {
   264→      mira.stopSession();
   265→      stt.stopListening();
   266→      setSessionActive(false);
   267→      setCanvasOutfits([]);
   268→      setCanvasOutfitIndex(0);
   269→      setActiveUser(null);
   270→      setKioskState("attract");
   271→      // Queue advancement happens server-side, queue_updated will fire next
   272→    };
   273→
   274→    socket.on("session_ended", handleSessionEnded);
   275→    return () => {
   276→      socket.off("session_ended", handleSessionEnded);
   277→    };
   278→    // eslint-disable-next-line react-hooks/exhaustive-deps
   279→  }, []);
   280→
   281→  // Listen for session_force_end — same as session_ended
   282→  useEffect(() => {
   283→    const handleForceEnd = (data: { user_id?: string }) => {
   284→      if (userId && data.user_id === userId) {
   285→        socket.emit("end_session", { user_id: userId });
   286→      }
   287→    };
   288→
   289→    socket.on("session_force_end", handleForceEnd);
   290→    return () => {
   291→      socket.off("session_force_end", handleForceEnd);
   292→    };
   293→  }, [userId]);
   294→
   295→  // Send transcripts to backend when mira stops speaking
   296→  useEffect(() => {
   297→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   298→      console.log("[Mirror] Flushing queued transcript:", pendingTranscriptRef.current);
   299→      socket.emit("mirror_event", {
   300→        user_id: userId,
   301→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   302→      });
   303→      pendingTranscriptRef.current = null;
   304→    }
   305→  }, [mira.isSpeaking, userId]);
   306→
   307→  // Forward final STT transcripts
   308→  useEffect(() => {
   309→    if (!stt.transcript || !userId) return;
   310→
   311→    if (mira.isSpeaking) {
   312→      console.log("[Mirror] Queuing transcript (mira speaking):", stt.transcript);
   313→      pendingTranscriptRef.current = stt.transcript;
   314→    } else {
   315→      console.log("[Mirror] Sending transcript to backend:", stt.transcript);
   316→      socket.emit("mirror_event", {
   317→        user_id: userId,
   318→        event: { type: "voice", transcript: stt.transcript },
   319→      });
   320→    }
   321→    // eslint-disable-next-line react-hooks/exhaustive-deps
   322→  }, [stt.transcript, userId]);
   323→
   324→  // Listen for snapshot requests from the backend
   325→  useEffect(() => {
   326→    const handleSnapshotRequest = () => {
   327→      const video = videoRef.current;
   328→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   329→
   330→      const canvas = document.createElement("canvas");
   331→      canvas.width = video.videoWidth;
   332→      canvas.height = video.videoHeight;
   333→      const ctx = canvas.getContext("2d");
   334→      if (!ctx) return;
   335→
   336→      ctx.drawImage(video, 0, 0);
   337→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   338→      const base64 = dataUrl.split(",")[1];
   339→
   340→      socket.emit("mirror_event", {
   341→        type: "snapshot",
   342→        image_base64: base64,
   343→        user_id: userId,
   344→      });
   345→    };
   346→
   347→    socket.on("request_snapshot", handleSnapshotRequest);
   348→    return () => {
   349→      socket.off("request_snapshot", handleSnapshotRequest);
   350→    };
   351→  }, [videoRef, userId]);
   352→
   353→  // Gesture handler
   354→  const handleGesture = useCallback(
   355→    (gesture: DetectedGesture) => {
   356→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   357→
   358→      setLastGesture(gesture.type);
   359→      gestureKeyRef.current += 1;
   360→      setGestureKey(gestureKeyRef.current);
   361→
   362→      if (canvasOutfits.length > 1) {
   363→        if (gesture.type === "swipe_left") {
   364→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   365→        } else if (gesture.type === "swipe_right") {
   366→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   367→        }
   368→      }
   369→
   370→      socket.emit("mirror_event", {
   371→        user_id: userId,
   372→        event: {
   373→          type: "gesture",
   374→          gesture: gesture.type,
   375→          confidence: gesture.confidence,
   376→          timestamp: gesture.timestamp,
   377→        },
   378→      });
   379→    },
   380→    [userId, canvasOutfits.length],
   381→  );
   382→
   383→  const { isLoading: isModelLoading, error: modelError } =
   384→    useGestureRecognizer({
   385→      videoRef,
   386→      isVideoReady: isCameraReady,
   387→      onGesture: handleGesture,
   388→    });
   389→
   390→  const handleStartSession = useCallback(() => {
   391→    if (!userId || isStarting || sessionActive) return;
   392→
   393→    // Unlock browser audio policy while we still have the user gesture context
   394→    const ctx = new AudioContext();
   395→    ctx.resume().then(() => ctx.close());
   396→
   397→    setIsStarting(true);
   398→
   399→    // Emit start via socket (server-side orchestrator)
   400→    socket.emit("start_session", { user_id: userId });
   401→  }, [userId, isStarting, sessionActive]);
   402→
   403→  const handleSkipUser = useCallback(() => {
   404→    if (!activeUser) return;
   405→    skipQueueUser(activeUser.id).catch(() => {});
   406→  }, [activeUser]);
   407→
   408→  return (
   409→    <main
   410→      style={{
   411→        position: "relative",
   412→        width: "100vw",
   413→        height: "100vh",
   414→        background: "#000",
   415→        overflow: "hidden",
   416→      }}
   417→    >
   418→      {/* Webcam feed (mirrored) */}
   419→      <video
   420→        ref={videoRef}
   421→        autoPlay
   422→        playsInline
   423→        muted
   424→        style={{
   425→          position: "absolute",
   426→          top: 0,
   427→          left: 0,
   428→          width: "100%",
   429→          height: "100%",
   430→          objectFit: "cover",
   431→          transform: "scaleX(-1)",
   432→        }}
   433→      />
   434→
   435→      {/* === ATTRACT STATE === */}
   436→      {kioskState === "attract" && (
   437→        <div
   438→          style={{
   439→            position: "absolute",
   440→            inset: 0,
   441→            zIndex: 20,
   442→            display: "flex",
   443→            flexDirection: "column",
   444→            alignItems: "center",
   445→            justifyContent: "center",
   446→            background: "rgba(0,0,0,0.7)",
   447→            backdropFilter: "blur(20px)",
   448→          }}
   449→        >
   450→          <h1
   451→            style={{
   452→              color: "#fff",
   453→              fontSize: "3rem",
   454→              fontWeight: 700,
   455→              marginBottom: 8,
   456→              letterSpacing: "-0.02em",
   457→            }}
   458→          >
   459→            Mirrorless
   460→          </h1>
   461→          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: "1.2rem", marginBottom: 40 }}>
   462→            Your AI stylist
   463→          </p>
   464→
   465→          <div
   466→            style={{
   467→              background: "#fff",
   468→              borderRadius: 16,
   469→              padding: 20,
   470→              marginBottom: 24,
   471→            }}
   472→          >
   473→            <QRCodeSVG
   474→              value={PHONE_URL}
   475→              size={180}
   476→              level="M"
   477→              includeMargin={false}
   478→            />
   479→          </div>
   480→
   481→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   482→            Scan the QR code with your phone
   483→          </p>
   484→        </div>
   485→      )}
   486→
   487→      {/* === WAITING STATE === */}
   488→      {kioskState === "waiting" && activeUser && (
   489→        <div
   490→          style={{
   491→            position: "absolute",
   492→            inset: 0,
   493→            zIndex: 20,
   494→            display: "flex",
   495→            flexDirection: "column",
   496→            alignItems: "center",
   497→            justifyContent: "center",
   498→            background: "rgba(0,0,0,0.6)",
   499→            backdropFilter: "blur(10px)",
   500→          }}
   501→        >
   502→          <p style={{ color: "rgba(255,255,255,0.5)", fontSize: "1rem", marginBottom: 8 }}>
   503→            Up next
   504→          </p>
   505→          <h2 style={{ color: "#fff", fontSize: "2.5rem", fontWeight: 700, marginBottom: 40 }}>
   506→            {activeUser.name}
   507→          </h2>
   508→          <div style={{ display: "flex", gap: 16 }}>
   509→            <button
   510→              onClick={handleStartSession}
   511→              disabled={isStarting}
   512→              style={{
   513→                padding: "16px 48px",
   514→                fontSize: "1.2rem",
   515→                fontWeight: 600,
   516→                color: "#fff",
   517→                background: "rgba(100, 140, 255, 0.8)",
   518→                border: "none",
   519→                borderRadius: 12,
   520→                cursor: "pointer",
   521→                backdropFilter: "blur(10px)",
   522→                boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   523→              }}
   524→            >
   525→              {isStarting ? "Starting..." : "Start Session"}
   526→            </button>
   527→            <button
   528→              onClick={handleSkipUser}
   529→              style={{
   530→                padding: "16px 32px",
   531→                fontSize: "1.2rem",
   532→                fontWeight: 600,
   533→                color: "#fff",
   534→                background: "rgba(255, 255, 255, 0.15)",
   535→                border: "1px solid rgba(255,255,255,0.3)",
   536→                borderRadius: 12,
   537→                cursor: "pointer",
   538→                backdropFilter: "blur(10px)",
   539→              }}
   540→            >
   541→              Skip
   542→            </button>
   543→          </div>
   544→          <WaitingCountdown />
   545→        </div>
   546→      )}
   547→
   548→      {/* === SESSION STATE === */}
   549→
   550→      {/* Clothing overlay canvas */}
   551→      {activeCanvasOutfit.length > 0 && currentPose && (
   552→        <ClothingCanvas
   553→          pose={currentPose}
   554→          items={activeCanvasOutfit}
   555→          width={1920}
   556→          height={1080}
   557→        />
   558→      )}
   559→
   560→      {/* Outfit dot indicator */}
   561→      {canvasOutfits.length > 1 && (
   562→        <div style={{ position: "absolute", bottom: 20, left: "50%", transform: "translateX(-50%)", display: "flex", gap: 8, zIndex: 18 }}>
   563→          {canvasOutfits.map((_, i) => (
   564→            <div key={i} style={{
   565→              width: 10, height: 10, borderRadius: "50%",
   566→              background: i === canvasOutfitIndex ? "#fff" : "rgba(255,255,255,0.3)",
   567→            }} />
   568→          ))}
   569→        </div>
   570→      )}
   571→
   572→      {/* Mira Video Avatar (fixed top-right corner) */}
   573→      {sessionActive && (
   574→        <div
   575→          style={{
   576→            position: "absolute",
   577→            top: 24,
   578→            right: 24,
   579→            zIndex: 10,
   580→          }}
   581→        >
   582→          <MiraVideoAvatar
   583→            emotion={mira.emotion}
   584→            state={mira.avatarState}
   585→            size={180}
   586→          />
   587→        </div>
   588→      )}
   589→
   590→      {/* Gesture visual feedback */}
   591→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   592→
   593→      {/* Price strip (bottom, when outfit active) */}
   594→      {sessionActive && activePriceItems.length > 0 && (
   595→        <PriceStrip items={activePriceItems} />
   596→      )}
   597→
   598→      {/* Voice indicator (bottom-left, session only) */}
   599→      {sessionActive && (
   600→        <VoiceIndicator
   601→          isListening={stt.isListening}
   602→          interimTranscript={stt.interimTranscript}
   603→        />
   604→      )}
   605→
   606→      {/* Error indicators */}
   607→      {(cameraError || modelError) && (
   608→        <div
   609→          style={{
   610→            position: "absolute",
   611→            bottom: 20,
   612→            left: 20,
   613→            color: "#f44",
   614→            fontSize: "1rem",
   615→            zIndex: 30,
   616→          }}
   617→        >
   618→          {cameraError && <div>Camera: {cameraError}</div>}
