  const handleSignInComplete = useCallback(
    (profile: UserProfile, selfieBase64: string | null, displayName: string) => {
      setUser(profile);
      localStorage.setItem(STORAGE_KEY, profile.id);

      // Fire-and-forget: update name, upload selfie, start scrape
