  function handleSubmit() {
    onSubmit({
      favorite_brands: brands.split(",").map((b) => b.trim()).filter(Boolean),
      style_preferences: styles,
      price_range: { min: priceMin, max: priceMax },
      size_info: {},
      gender,
      occasions,
    });
