   691→  useEffect(() => {
   692→    const timer = setInterval(() => {
   693→      setRemaining((s) => {
   694→        if (s <= 0) return 0;
   695→        return s - 1;
   696→      });
   697→    }, 1000);
   698→    return () => clearInterval(timer);
   699→  }, []);
   700→
   701→  const minutes = Math.floor(remaining / 60);
   702→  const seconds = remaining % 60;
   703→
   704→  return (
   705→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   706→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   707→    </p>
   708→  );
   709→}
